body:
Hello,

I have this example code:

```
module
   iotst
     (
      inout single_bit_io,
      inout bidir_single_bit_io,
      inout [63:0] bus_64_io,
      inout [63:0] bidir_bus_64_io,
      inout [127:0] bus_128_io,
      inout [127:0] bidir_bus_128_io,
      input drv_en
      );

   timeunit 1ns;
   timeprecision 1ps;

   bit 	    rand_bit;
   
   assign single_bit_io       = 1'bz;
   assign bidir_single_bit_io = drv_en ? rand_bit : 1'bz;
   assign bus_64_io           = {64{1'bz}};
   assign bidir_bus_64_io     = drv_en ? {64{rand_bit}} : {64{1'bz}};
   assign bus_128_io          = {128{1'bz}};
   assign bidir_bus_128_io    = drv_en ? {128{rand_bit}} : {128{1'bz}};

   initial
     begin
	rand_bit = (($urandom_range(1,0) & 'd1) == 'd1);
	#(1ns) $display("1ns");
	rand_bit = ~rand_bit;
	#(1ns) $display("2ns");
	rand_bit = ~rand_bit;
	#(1ns) $finish(1);
     end

   final
     begin
	$display("All done at %t", $time);
     end
   
   always @(drv_en
	    or 
	    bidir_single_bit_io
	    or 
	    bidir_bus_64_io
	    or 
	    bidir_bus_128_io)
     begin
	$display("rand_bit = %b", rand_bit);
	if (drv_en)
	  begin
	     $display("bidir_single_bit_io = %b", bidir_single_bit_io);
	     $display("bidir_bus_64_io = %b", bidir_bus_64_io);
	     $display("bidir_bus_128_io = %b", bidir_bus_128_io);

	     if (bidir_single_bit_io != rand_bit)
	       begin
		  $display("%%Error: bidir_single_bit_io is wrong");
	       end

	     if (bidir_bus_64_io != {64{rand_bit}})
	       begin
		  $display("%%Error: bidir_bus_64_io is wrong");
		  $display("Should be bidir_bus_64_io = %b", {64{rand_bit}});
	       end

	     if (bidir_bus_128_io != {128{rand_bit}})
	       begin
		  $display("%%Error: bidir_bus_128_io is wrong");
		  $display("Should be bidir_bus_128 = %b", {128{rand_bit}});
	       end
	  end
     end
   
endmodule

```

I want to drive it with this main function:

```
#include "verilated.h"
#include "Viotst.h"
#include <stdio.h>

//======================

int main(int argc, char** argv, char**) {
  // Setup context, defaults, and parse command line
  Verilated::debug(0);
  const std::unique_ptr<VerilatedContext> contextp{new VerilatedContext};
  contextp->commandArgs(argc, argv);
  
  // Construct the Verilated model, from Vtop.h generated from Verilating
  const std::unique_ptr<Viotst> topp{new Viotst{contextp.get()}};

  // Initial input
  topp->drv_en = 1;
  topp->single_bit_io = 0;
  topp->bidir_single_bit_io = 0;
  topp->bus_64_io = 0;
  topp->bidir_bus_64_io = 0;
  topp->bus_128_io[0] = 0;
  topp->bus_128_io[1] = 0;
  topp->bus_128_io[2] = 0;
  topp->bus_128_io[3] = 0;
  topp->bidir_bus_128_io[0] = 0;
  topp->bidir_bus_128_io[1] = 0;
  topp->bidir_bus_128_io[2] = 0;
  topp->bidir_bus_128_io[3] = 0;

  // Simulate until $finish
  while (!contextp->gotFinish()) {
    // Evaluate model
    topp->eval();

    // Advance time (to scheduled events)
    if (!topp->eventsPending()) break;
    contextp->time(topp->nextTimeSlot());

    printf("bidir_single_bit_io__en = %x", topp->bidir_single_bit_io__en);
    printf("bidir_bus_64_io__en = %x", topp->bidir_bus_64_io__en);
    printf("bidir_bus_128_io__en = %x,%x,%x,%x",
	   topp->bidir_bus_128_io[3],
	   topp->bidir_bus_128_io[2],
	   topp->bidir_bus_128_io[1],
	   topp->bidir_bus_128_io[0]);

    printf("bidir_single_bit_io = %x", topp->bidir_single_bit_io__out);
    printf("bidir_bus_64_io = %x", topp->bidir_bus_64_io__out);
    printf("bidir_bus_128_io = %x,%x,%x,%x",
	   topp->bidir_bus_128_io__out[3],
	   topp->bidir_bus_128_io__out[2],
	   topp->bidir_bus_128_io__out[1],
	   topp->bidir_bus_128_io__out[0]);
  }
  
  if (!contextp->gotFinish()) {
    printf("Exiting without $finish; no events left, time was %ld\n",
	   contextp->time());
    puts("final next:");
  }
  
  // Final model cleanup
  topp->final();
  return 0;
}
```

I compile it with:

`verilator -exe -timing -cc -build iotst.sv main.cpp --top-module iotst`

I get:

```
